export default function findTwin(rootA, rootB, targetA) {
  if (!rootA || !rootB) return null;
  if (rootA === targetA) return rootB;
  const childrenA = rootA.children;
  const childrenB = rootB.children;
  for (let i = 0; i < childrenA.length; i++) {
    const found = findTwin(childrenA[i], childrenB[i], targetA);
    if (found) return found;
  }
  return null;
}
